  await page.goto(fileUrl(indexPath));
  // fill board with no adjacent equals
  await page.evaluate(() => {
    (window as any).setSeed(7);
    (window as any).setBoard([
      [2,4,2,4],
      [4,2,4,2],
      [2,4,2,4],
      [4,2,4,2]
    ]);
  });
